export enum ProcessStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING', // Transcribing and translating
  GENERATING_AUDIO = 'GENERATING_AUDIO', // TTS
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface DubbingResult {
  originalText: string;
  translatedText: string;
  audioBuffer: AudioBuffer | null;
}

export interface ProcessingError {
  message: string;
}

// Base64 decoding
function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// PCM Data decoding to AudioBuffer
export async function decodeAudioData(
  base64String: string,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1
): Promise<AudioBuffer> {
  const data = decode(base64String);
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      // Convert Int16 to Float32 [-1.0, 1.0]
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const fileToGenerativePart = async (file: File): Promise<{ inlineData: { data: string; mimeType: string } }> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64String = reader.result as string;
      // Remove the data URL prefix (e.g., "data:video/mp4;base64,")
      const base64Data = base64String.split(',')[1];
      resolve({
        inlineData: {
          data: base64Data,
          mimeType: file.type,
        },
      });
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

import { GoogleGenAI, Modality } from "@google/genai";
import { fileToGenerativePart, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

// 1. Analyze Video: English Audio -> Uzbek Text
export const analyzeAndTranslateVideo = async (videoFile: File): Promise<{ translatedText: string; originalTranscription: string }> => {
  if (!apiKey) throw new Error("API Key not found");

  const ai = new GoogleGenAI({ apiKey });

  const videoPart = await fileToGenerativePart(videoFile);

  const prompt = `
    Listen carefully to the English speech in this video. 
    1. Transcribe the English text accurately.
    2. Translate the English text into natural, colloquial Uzbek suitable for social media (Instagram).

    Output JSON format:
    {
      "english_transcription": "...",
      "uzbek_translation": "..."
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        videoPart,
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from Gemini.");

  try {
    const json = JSON.parse(text);
    return {
      translatedText: json.uzbek_translation,
      originalTranscription: json.english_transcription
    };
  } catch (e) {
    console.error("Failed to parse JSON", e);
    // Fallback if JSON fails, though we requested JSON mode
    return { translatedText: text, originalTranscription: "Not available" };
  }
};

// 2. Generate Audio: Uzbek Text -> Audio Buffer
export const generateUzbekSpeech = async (text: string, audioContext: AudioContext): Promise<AudioBuffer> => {
  if (!apiKey) throw new Error("API Key not found");

  const ai = new GoogleGenAI({ apiKey });

  // Use the TTS specific model
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Fenrir has a deeper tone, often good for narration
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data returned from Gemini.");
  }

  // Decode using the raw PCM decoder logic provided in strict instructions
  return await decodeAudioData(base64Audio, audioContext, 24000, 1);
};

