export enum ProcessStatus {
  IDLE = 'IDLE',
  ANALYZING = 'ANALYZING', // Transcribing and translating
  GENERATING_AUDIO = 'GENERATING_AUDIO', // TTS
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

export interface DubbingResult {
  originalText: string;
  translatedText: string;
  audioBuffer: AudioBuffer | null;
  fileName: string; // Video topic slug for filename
}

export interface ProcessingError {
  message: string;
}

import { GoogleGenAI, Modality } from "@google/genai";
import { fileToGenerativePart, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

// 1. Analyze Video: English Audio -> Uzbek Text & Topic
export const analyzeAndTranslateVideo = async (videoFile: File): Promise<{ translatedText: string; originalTranscription: string; topicSlug: string }> => {
  if (!apiKey) throw new Error("API Key not found");

  const ai = new GoogleGenAI({ apiKey });

  const videoPart = await fileToGenerativePart(videoFile);

  const prompt = `
    Listen carefully to the English speech in this video. 
    1. Transcribe the English text accurately.
    2. Translate the English text into natural, colloquial Uzbek suitable for social media (Instagram).
    3. CRITICAL: Keep the Uzbek translation CONCISE and SHORT. It must match the duration of the original speech. Avoid long sentences.
    4. Create a short, file-safe filename slug based on the video topic (e.g., 'Sarimsoqning_vazifasi'). Use only Uzbek letters, numbers, and underscores. No spaces. Key: 'topic_slug'.

    Output JSON format:
    {
      "english_transcription": "...",
      "uzbek_translation": "...",
      "topic_slug": "..."
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        videoPart,
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from Gemini.");

  try {
    const json = JSON.parse(text);
    return {
      translatedText: json.uzbek_translation,
      originalTranscription: json.english_transcription,
      topicSlug: json.topic_slug || 'video_dublyaj' // Fallback
    };
  } catch (e) {
    console.error("Failed to parse JSON", e);
    // Fallback if JSON fails
    return { 
      translatedText: text, 
      originalTranscription: "Not available",
      topicSlug: 'video_dublyaj'
    };
  }
};

// 2. Generate Audio: Uzbek Text -> Audio Buffer
export const generateUzbekSpeech = async (text: string, audioContext: AudioContext): Promise<AudioBuffer> => {
  if (!apiKey) throw new Error("API Key not found");

  const ai = new GoogleGenAI({ apiKey });

  // Use the TTS specific model
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Fenrir' }, // Fenrir has a deeper tone, often good for narration
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data returned from Gemini.");
  }

  // Decode using the raw PCM decoder logic provided in strict instructions
  return await decodeAudioData(base64Audio, audioContext, 24000, 1);
};

