  const getVideoDuration = (file: File): Promise<number> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');
      video.preload = 'metadata';
      video.onloadedmetadata = () => {
        window.URL.revokeObjectURL(video.src);
        resolve(video.duration);
      };
      video.onerror = () => {
        resolve(0); // Fallback if duration fails
      };
      video.src = URL.createObjectURL(file);
    });
  };

  const handleFileSelect = async (file: File) => {
    setVideoFile(file);
    setStatus(ProcessStatus.ANALYZING);
    setError(null);

    try {
      // Step 0: Get Video Duration
      const duration = await getVideoDuration(file);
      console.log(`Video duration detected: ${duration} seconds`);

      // Step 1: Analyze and Translate (Pass duration to prompt)
      const { translatedText, originalTranscription, topicSlug } = await analyzeAndTranslateVideo(file, duration);

      setStatus(ProcessStatus.GENERATING_AUDIO);

      // Step 2: Generate Speech
      // Create a temporary audio context to decode the data
      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await generateUzbekSpeech(translatedText, audioCtx);
