const apiKey = process.env.API_KEY || '';

// 1. Analyze Video: English Audio -> Uzbek Text & Topic
// Now accepts 'duration' to guide the length of the generated text
export const analyzeAndTranslateVideo = async (videoFile: File, duration: number): Promise<{ translatedText: string; originalTranscription: string; topicSlug: string }> => {
  if (!apiKey) throw new Error("API Key topilmadi. Iltimos, API kaliti sozlanganligini tekshiring.");

  const ai = new GoogleGenAI({ apiKey });

  const videoPart = await fileToGenerativePart(videoFile);

  // We calculate approx word count needed. 
  // Average speaking rate is ~2-2.5 words per second for clear TTS.
  const targetWordCount = Math.max(5, Math.ceil(duration * 2)); 

  const prompt = `
    Analyze this video.

    METADATA:
    - Video Duration: ${Math.ceil(duration)} seconds.
    - Target Word Count for Translation: Approximately ${targetWordCount} words.

    TASKS:
    1. Transcribe the English speech accurately.
    2. Translate it into natural, colloquial Uzbek (Instagram style).
    3. **TIMING CONTROL (CRITICAL):** 
       - The Uzbek translation MUST take approximately ${Math.ceil(duration)} seconds to speak aloud.
       - If the video is long (e.g. 8+ seconds per scene) but the English text is short, you MUST ELABORATE and add descriptive details in Uzbek to fill the time.
       - If the video is short, be concise.
       - The goal is for the audio to match the video length exactly.
    4. Create a file-safe slug for the topic (e.g., 'ovqat_tayyorlash').

    Output JSON format:
    {
      "english_transcription": "...",
      "uzbek_translation": "...",
      "topic_slug": "..."
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        videoPart,
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from Gemini.");

  try {
    const json = JSON.parse(text);
    return {
      translatedText: json.uzbek_translation,
      originalTranscription: json.english_transcription,
      topicSlug: json.topic_slug || 'video_dublyaj' // Fallback
    };
  } catch (e) {
    console.error("Failed to parse JSON", e);
    // Fallback if JSON fails
    return { 
      translatedText: text, 
      originalTranscription: "Not available",
      topicSlug: 'video_dublyaj'
    };
  }
};

