import React, { useRef, useEffect, useState, useCallback } from 'react';
import { DubbingResult } from '../types';

interface DubbingStudioProps {
  videoFile: File;
  result: DubbingResult;
  onReset: () => void;
}

const DubbingStudio: React.FC<DubbingStudioProps> = ({ videoFile, result, onReset }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRendering, setIsRendering] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string>('');

  // Audio Context Ref to manage playback state
  const audioContextRef = useRef<AudioContext | null>(null);
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);

  useEffect(() => {
    const url = URL.createObjectURL(videoFile);
    setVideoUrl(url);

    // Initialize Audio Context
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

    return () => {
      URL.revokeObjectURL(url);
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, [videoFile]);

  const stopAudio = useCallback(() => {
    if (audioSourceRef.current) {
      try {
        audioSourceRef.current.stop();
        audioSourceRef.current.disconnect();
      } catch (e) {
        // Ignore errors if already stopped
      }
      audioSourceRef.current = null;
    }
  }, []);

  // Helper to calculate sync rate
  const getSyncFactor = () => {
    if (!videoRef.current || !result.audioBuffer) return 1.0;
    const videoDuration = videoRef.current.duration;
    const audioDuration = result.audioBuffer.duration;

    // The logic: We want Audio and Video to end at the same time.
    // If Audio is 8s and Video is 8s, rate is 1.0.
    // If Audio is 8s and Video is 4s, Video must play at 0.5x speed (slow down) to match audio? 
    // Wait, if Audio (8s) > Video (4s), we need to stretch Video to 8s. 
    // Rate = VideoDuration / AudioDuration = 4 / 8 = 0.5.

    if (audioDuration > 0 && videoDuration > 0) {
      // Limit the speed change to avoid looking too ridiculous (0.5x to 2.0x)
      const rawRate = videoDuration / audioDuration;
      return Math.min(Math.max(rawRate, 0.5), 2.0); 
    }
    return 1.0;
  };

  const playDubbed = useCallback(async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current) return;

    // Resume context if suspended (browser policy)
    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    // Stop any existing audio
    stopAudio();

    // Create source
    const source = audioContextRef.current.createBufferSource();
    source.buffer = result.audioBuffer;
    source.connect(audioContextRef.current.destination);

    // Sync Video logic
    const playbackRate = getSyncFactor();
    videoRef.current.playbackRate = playbackRate;

    // Reset position
    videoRef.current.currentTime = 0;
    videoRef.current.muted = true; // Mute original English

    // Start both
    await videoRef.current.play();
    source.start(0);

    audioSourceRef.current = source;
    setIsPlaying(true);

    // Cleanup on end
    source.onended = () => {
      setIsPlaying(false);
      videoRef.current?.pause(); 
    };

    videoRef.current.onended = () => {
      // If video ends before audio (shouldn't happen with sync logic, but safety check)
      if (videoRef.current?.playbackRate === 1) {
         // wait for audio
      } else {
         setIsPlaying(false);
         stopAudio();
      }
    };

  }, [result.audioBuffer, stopAudio]);

  const pausePlayback = () => {
    if (videoRef.current) {
      videoRef.current.pause();
    }
    stopAudio();
    setIsPlaying(false);
  };

  const handleDownload = async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current) return;

    setIsRendering(true);
    stopAudio();

    try {
      // 1. Setup Media Recording
      // We capture the video stream from the video element
      const stream: any = (videoRef.current as any).captureStream ? (videoRef.current as any).captureStream() : (videoRef.current as any).mozCaptureStream();

      // We create a destination for the audio to record it
      const audioDest = audioContextRef.current.createMediaStreamDestination();
      const source = audioContextRef.current.createBufferSource();
      source.buffer = result.audioBuffer;
      source.connect(audioDest);
      source.connect(audioContextRef.current.destination); // Optional: let user hear it while rendering

      // Combine tracks
      const combinedStream = new MediaStream([
        ...stream.getVideoTracks(),
        ...audioDest.stream.getAudioTracks()
      ]);

      // Determine mime type
      const mimeType = MediaRecorder.isTypeSupported("video/mp4") 
        ? "video/mp4" 
        : "video/webm";

      // High bitrate for better quality (5 Mbps)
      const recorder = new MediaRecorder(combinedStream, { 
        mimeType,
        videoBitsPerSecond: 5000000 
      });

      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunks.push(e.data);
      };

      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;

        // Use the generated filename slug or fallback to 'video'
        const filename = result.fileName || 'video';
        a.download = `${filename}.mp4`; 

        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        setIsRendering(false);
        setIsPlaying(false);

        // Restore playback rate to normal
        if (videoRef.current) videoRef.current.playbackRate = 1;
      };

      // 2. Playback for recording
      recorder.start();

      // Sync Logic applied to recording playback
      const playbackRate = getSyncFactor();
      videoRef.current.playbackRate = playbackRate;
      videoRef.current.currentTime = 0;
      videoRef.current.muted = true; // IMPORTANT: Mute the VIDEO element so we don't record original audio

      await videoRef.current.play();
      source.start(0);

      setIsPlaying(true);
      audioSourceRef.current = source;

      // Stop recording when audio ends (since audio drives the content)
      source.onended = () => {
        recorder.stop();
        videoRef.current?.pause();
      };

    } catch (e) {
      console.error("Recording failed", e);
      setIsRendering(false);
      alert("Video yuklashda xatolik: Brauzeringiz ushbu funksiyani qo'llab-quvvatlamasligi mumkin.");
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">

        {/* Left Column: Video */}
        <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-gray-700">
          <h3 className="text-lg font-semibold mb-3 text-blue-300">
            Original Video 
            {isRendering && <span className="ml-2 text-xs text-red-400 animate-pulse">● Yozilmoqda (Kuting)...</span>}
          </h3>
          <div className="relative aspect-[9/16] bg-black rounded-lg overflow-hidden mx-auto max-h-[500px]">
            <video 
              ref={videoRef}
              src={videoUrl}
              className="w-full h-full object-contain"
              playsInline
              controls={false}
            />
          </div>
        </div>

        {/* Right Column: Text & Translation */}
        <div className="flex flex-col gap-4">
          <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-gray-700 flex-1">
            <h3 className="text-sm font-semibold uppercase tracking-wider text-gray-400 mb-2">English Transcription</h3>
            <p className="text-gray-300 text-sm italic border-l-2 border-gray-600 pl-3">
              "{result.originalText}"
            </p>
          </div>

          <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-blue-500 flex-1 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-2 bg-blue-600 text-xs font-bold rounded-bl-lg">O'zbekcha</div>
            <h3 className="text-sm font-semibold uppercase tracking-wider text-blue-300 mb-2">Tarjima (Uzbek)</h3>
            <p className="text-white text-lg font-medium leading-relaxed">
              "{result.translatedText}"
            </p>
          </div>

          {/* Controls */}
          <div className="bg-gray-800 rounded-xl p-6 shadow-lg border border-gray-700 mt-auto">
             <div className="flex flex-col gap-3">
               <div className="flex gap-4">
                 {!isPlaying && !isRendering ? (
                   <button 
                    onClick={playDubbed}
                    className="flex-1 bg-green-600 hover:bg-green-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
                   >
                     <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                     Ko'rish (Play)
                   </button>
                 ) : (
                   <button 
                    onClick={pausePlayback}
                    disabled={isRendering}
                    className={`flex-1 bg-red-600 hover:bg-red-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 ${isRendering ? 'opacity-50 cursor-not-allowed' : ''}`}
                   >
                     <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                     Pause
                   </button>
                 )}

                 <button 
                  onClick={onReset}
                  disabled={isRendering}
                  className="px-4 py-3 border border-gray-600 rounded-lg hover:bg-gray-700 text-gray-300 transition-colors"
                 >
                   Yangi
                 </button>
               </div>

               <button 
                onClick={handleDownload}
                disabled={isRendering}
                className={`w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 ${isRendering ? 'opacity-50 cursor-not-allowed' : ''}`}
               >
                 {isRendering ? (
                    <>
                      <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                      </svg>
                      Videoga yozilmoqda...
                    </>
                 ) : (
                    <>
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      Videoni yuklash ({result.fileName || 'video'}.mp4)
                    </>
                 )}
               </button>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

