import React, { useRef, useEffect, useState, useCallback } from 'react';
import { DubbingResult } from '../types';

interface DubbingStudioProps {
  videoFile: File;
  result: DubbingResult;
  onReset: () => void;
}

const DubbingStudio: React.FC<DubbingStudioProps> = ({ videoFile, result, onReset }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRendering, setIsRendering] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [bgVolume, setBgVolume] = useState(0.15); // 15% original volume by default

  // Audio Context Ref to manage playback state and mixing
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const ttsGainRef = useRef<GainNode | null>(null);

  useEffect(() => {
    const url = URL.createObjectURL(videoFile);
    setVideoUrl(url);

    // Initialize Audio Context
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    // Create gain node for TTS
    ttsGainRef.current = audioContextRef.current.createGain();
    ttsGainRef.current.connect(audioContextRef.current.destination);

    return () => {
      URL.revokeObjectURL(url);
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, [videoFile]);

  const stopAudio = useCallback(() => {
    if (ttsSourceRef.current) {
      try {
        ttsSourceRef.current.stop();
        ttsSourceRef.current.disconnect();
      } catch (e) {}
      ttsSourceRef.current = null;
    }
  }, []);

  const getSyncFactor = () => {
    if (!videoRef.current || !result.audioBuffer) return 1.0;
    const videoDuration = videoRef.current.duration;
    const audioDuration = result.audioBuffer.duration;

    if (audioDuration > 0 && videoDuration > 0) {
      const rawRate = videoDuration / audioDuration;
      return Math.min(Math.max(rawRate, 0.5), 2.0); 
    }
    return 1.0;
  };

  // Live Playback Logic
  const playDubbed = useCallback(async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current || !ttsGainRef.current) return;

    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    stopAudio();

    // Setup TTS Source
    const source = audioContextRef.current.createBufferSource();
    source.buffer = result.audioBuffer;
    source.connect(ttsGainRef.current);

    // Sync Video
    const playbackRate = getSyncFactor();
    videoRef.current.playbackRate = playbackRate;
    videoRef.current.currentTime = 0;

    // MIXING: Don't mute, set volume for background effect
    videoRef.current.muted = false;
    videoRef.current.volume = bgVolume; 

    // Start
    await videoRef.current.play();
    source.start(0);

    ttsSourceRef.current = source;
    setIsPlaying(true);

    source.onended = () => {
      setIsPlaying(false);
      videoRef.current?.pause(); 
    };

    videoRef.current.onended = () => {
      if (videoRef.current?.playbackRate !== 1) {
         setIsPlaying(false);
         stopAudio();
      }
    };

  }, [result.audioBuffer, stopAudio, bgVolume]);

  const pausePlayback = () => {
    if (videoRef.current) videoRef.current.pause();
    stopAudio();
    setIsPlaying(false);
  };

  // Recording Logic (Advanced Mixing)
  const handleDownload = async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current) return;

    setIsRendering(true);
    stopAudio();

    try {
      // Create a destination for the recording mixer
      const dest = audioContextRef.current.createMediaStreamDestination();

      // 1. TTS Track -> Mixer
      const ttsSource = audioContextRef.current.createBufferSource();
      ttsSource.buffer = result.audioBuffer;
      ttsSource.connect(dest); // Full volume for TTS

      // 2. Video Audio -> Mixer (Tricky part: need MediaElementSource)
      // Note: createMediaElementSource can only be called once per element. 
      // Safest way for simple export is to rely on captureStream logic if possible, 
      // OR play the video loudly and capture it. 

      // Simpler approach for client-side export reliability:
      // We will play the video with the volume set by user.
      // We assume captureStream() picks up the video element's audio output.

      let stream: MediaStream;
      const vid = videoRef.current as any;
      if (vid.captureStream) {
        stream = vid.captureStream();
      } else if (vid.mozCaptureStream) {
        stream = vid.mozCaptureStream();
      } else {
        throw new Error("Browser capture not supported");
      }

      // If video has audio tracks, they are in `stream`. 
      // We need to ADD the TTS track to this stream.
      // However, MediaRecorder usually only records the first audio track or requires mixing.

      // Let's Mix manually into `dest`:
      // Since we can't easily hook MediaElementSource without CORS or re-connection issues often,
      // We will add the TTS audio track to the video stream and hope browser mixes them 
      // OR we just use the TTS audio + Video visual (if user wants 0 bg noise).

      // ROBUST MIXING STRATEGY:
      // We will create a NEW stream composed of:
      // - The Video Track from video element
      // - The Audio Track from 'dest' (which will contain TTS)
      // *BUT* we miss the background music this way unless we connect video to 'dest'.

      // Let's try to connect the video element to the AudioContext if not already connected.
      // If that fails, we fallback to just TTS.
      try {
         const videoSource = audioContextRef.current.createMediaElementSource(videoRef.current);
         const bgGain = audioContextRef.current.createGain();
         bgGain.gain.value = bgVolume;
         videoSource.connect(bgGain);
         bgGain.connect(dest);
         // Also connect back to destination so user can hear it while rendering? 
         // careful of echo. let's mute the video element effectively by disconnecting from hardware?
         // No, createMediaElementSource disconnects it from speakers automatically.
         bgGain.connect(audioContextRef.current.destination);
      } catch (e) {
         console.warn("Could not create MediaElementSource (already connected?)", e);
         // Fallback: Just recording TTS, video audio might be lost or duplicated depending on browser.
      }

      const combinedStream = new MediaStream([
        ...stream.getVideoTracks(),
        ...dest.stream.getAudioTracks()
      ]);

      const mimeType = MediaRecorder.isTypeSupported("video/mp4") ? "video/mp4" : "video/webm";
      const recorder = new MediaRecorder(combinedStream, { mimeType, videoBitsPerSecond: 5000000 });
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `${result.fileName || 'dubbed_video'}.mp4`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        setIsRendering(false);
        setIsPlaying(false);
        if (videoRef.current) {
            videoRef.current.playbackRate = 1;
            videoRef.current.volume = 1; // Reset volume
        }
      };

      recorder.start();

      // Playback setup
      const playbackRate = getSyncFactor();
      videoRef.current.playbackRate = playbackRate;
      videoRef.current.currentTime = 0;
      videoRef.current.volume = bgVolume; // Ensure volume is set

      await videoRef.current.play();
      ttsSource.start(0);
      ttsSourceRef.current = ttsSource; // store to stop if needed

      ttsSource.onended = () => {
        recorder.stop();
        videoRef.current?.pause();
      };

    } catch (e) {
      console.error("Recording failed", e);
      setIsRendering(false);
      alert("Yuklashda xatolik yuz berdi. Iltimos, qayta urinib ko'ring.");
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">

        {/* Left: Video */}
        <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-gray-700">
          <h3 className="text-lg font-semibold mb-3 text-blue-300">
            Natija {isRendering && <span className="ml-2 text-xs text-red-400 animate-pulse">● Yozilmoqda...</span>}
          </h3>
          <div className="relative aspect-[9/16] bg-black rounded-lg overflow-hidden mx-auto max-h-[500px]">
            <video 
              ref={videoRef}
              src={videoUrl}
              className="w-full h-full object-contain"
              playsInline
              controls={false}
            />
          </div>

          {/* Volume Control */}
          <div className="mt-4 bg-gray-900/50 p-3 rounded-lg border border-gray-600">
            <div className="flex justify-between text-xs text-gray-400 mb-1">
               <span>Fon ovozi (Original)</span>
               <span>{Math.round(bgVolume * 100)}%</span>
            </div>
            <input 
              type="range" 
              min="0" 
              max="0.5" // Limit max volume to 50% so voice is always clearer
              step="0.01" 
              value={bgVolume}
              onChange={(e) => setBgVolume(parseFloat(e.target.value))}
              disabled={isPlaying || isRendering}
              className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-blue-500"
            />
          </div>
        </div>

        {/* Right: Text & Controls */}
        <div className="flex flex-col gap-4">
          <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-blue-500 flex-1 relative overflow-hidden flex flex-col">
            <div className="absolute top-0 right-0 p-2 bg-blue-600 text-xs font-bold rounded-bl-lg">O'zbekcha</div>
            <h3 className="text-sm font-semibold uppercase tracking-wider text-blue-300 mb-2">Dublyaj Matni</h3>
            <div className="overflow-y-auto flex-1 max-h-[300px] pr-2 custom-scrollbar">
                <p className="text-white text-lg font-medium leading-relaxed">
                "{result.translatedText}"
                </p>
            </div>
          </div>

          <div className="bg-gray-800 rounded-xl p-6 shadow-lg border border-gray-700 mt-auto">
             <div className="flex flex-col gap-3">
               <div className="flex gap-4">
                 {!isPlaying && !isRendering ? (
                   <button 
                    onClick={playDubbed}
                    className="flex-1 bg-green-600 hover:bg-green-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2"
                   >
                     <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
                     Eshitish
                   </button>
                 ) : (
                   <button 
                    onClick={pausePlayback}
                    disabled={isRendering}
                    className={`flex-1 bg-red-600 hover:bg-red-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 ${isRendering ? 'opacity-50 cursor-not-allowed' : ''}`}
                   >
                     <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zM7 8a1 1 0 012 0v4a1 1 0 11-2 0V8zm5-1a1 1 0 00-1 1v4a1 1 0 102 0V8a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
                     To'xtatish
                   </button>
                 )}

                 <button 
                  onClick={onReset}
                  disabled={isRendering}
                  className="px-4 py-3 border border-gray-600 rounded-lg hover:bg-gray-700 text-gray-300 transition-colors"
                 >
                   Yangi
                 </button>
               </div>

               <button 
                onClick={handleDownload}
                disabled={isRendering}
                className={`w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-3 px-6 rounded-lg transition-colors flex items-center justify-center gap-2 ${isRendering ? 'opacity-50 cursor-not-allowed' : ''}`}
               >
                 {isRendering ? (
                    <>Spinning...</> // Simplified spinner for brevity
                 ) : (
                    <>
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                      Yuklab Olish (MP4)
                    </>
                 )}
               </button>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DubbingStudio;

