import React, { useRef, useEffect, useState, useCallback } from 'react';
import { DubbingResult } from '../types';

interface DubbingStudioProps {
  videoFile: File;
  result: DubbingResult;
  onReset: () => void;
}

const DubbingStudio: React.FC<DubbingStudioProps> = ({ videoFile, result, onReset }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRendering, setIsRendering] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string>('');
  const [bgVolume, setBgVolume] = useState(0.15); // 15% original volume by default
  const [audioSpeed, setAudioSpeed] = useState(1.1); // Default 1.1x speed

  // Audio Context Ref to manage playback state and mixing
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const ttsGainRef = useRef<GainNode | null>(null);

  useEffect(() => {
    const url = URL.createObjectURL(videoFile);
    setVideoUrl(url);

    // Initialize Audio Context
    audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    // Create gain node for TTS
    ttsGainRef.current = audioContextRef.current.createGain();
    ttsGainRef.current.connect(audioContextRef.current.destination);

    return () => {
      URL.revokeObjectURL(url);
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }
    };
  }, [videoFile]);

  const stopAudio = useCallback(() => {
    if (ttsSourceRef.current) {
      try {
        ttsSourceRef.current.stop();
        ttsSourceRef.current.disconnect();
      } catch (e) {}
      ttsSourceRef.current = null;
    }
  }, []);

  const getSyncFactor = useCallback(() => {
    if (!videoRef.current || !result.audioBuffer) return 1.0;
    const videoDuration = videoRef.current.duration;
    // Calculate effective audio duration based on speed
    const effectiveAudioDuration = result.audioBuffer.duration / audioSpeed;

    if (effectiveAudioDuration > 0 && videoDuration > 0) {
      const rawRate = videoDuration / effectiveAudioDuration;
      // If audio is still longer than video (rawRate < 1), we slow down video.
      // If audio is shorter (rawRate > 1), we speed up video or keep it 1.
      return Math.min(Math.max(rawRate, 0.5), 2.0); 
    }
    return 1.0;
  }, [result.audioBuffer, audioSpeed]);

  // Live Playback Logic
  const playDubbed = useCallback(async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current || !ttsGainRef.current) return;

    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    stopAudio();

    // Setup TTS Source
    const source = audioContextRef.current.createBufferSource();
    source.buffer = result.audioBuffer;
    source.playbackRate.value = audioSpeed; // Apply speed
    source.connect(ttsGainRef.current);

    // Sync Video
    const playbackRate = getSyncFactor();
    videoRef.current.playbackRate = playbackRate;
    videoRef.current.currentTime = 0;

    // MIXING
    videoRef.current.muted = false;
    videoRef.current.volume = bgVolume; 

    // Start
    await videoRef.current.play();
    source.start(0);

    ttsSourceRef.current = source;
    setIsPlaying(true);

    source.onended = () => {
      setIsPlaying(false);
      videoRef.current?.pause(); 
    };

    videoRef.current.onended = () => {
      // If video ends but audio is still playing (video was faster), wait for audio.
      // If video ends and audio ended (sync), all good.
      // We rely on audio source onended mostly because audio drives the content here.
    };

  }, [result.audioBuffer, stopAudio, bgVolume, audioSpeed, getSyncFactor]);

  const pausePlayback = () => {
    if (videoRef.current) videoRef.current.pause();
    stopAudio();
    setIsPlaying(false);
  };

  // Recording Logic
  const handleDownload = async () => {
    if (!videoRef.current || !result.audioBuffer || !audioContextRef.current) return;

    setIsRendering(true);
    stopAudio();

    try {
      const dest = audioContextRef.current.createMediaStreamDestination();

      // 1. TTS Track -> Mixer
      const ttsSource = audioContextRef.current.createBufferSource();
      ttsSource.buffer = result.audioBuffer;
      ttsSource.playbackRate.value = audioSpeed; // Apply speed to export too
      ttsSource.connect(dest);

      // 2. Video Audio Mixing
      let stream: MediaStream;
      const vid = videoRef.current as any;
      if (vid.captureStream) {
        stream = vid.captureStream();
      } else if (vid.mozCaptureStream) {
        stream = vid.mozCaptureStream();
      } else {
        throw new Error("Browser capture not supported");
      }

      try {
         const videoSource = audioContextRef.current.createMediaElementSource(videoRef.current);
         const bgGain = audioContextRef.current.createGain();
         bgGain.gain.value = bgVolume;
         videoSource.connect(bgGain);
         bgGain.connect(dest);
         bgGain.connect(audioContextRef.current.destination);
      } catch (e) {
         console.warn("Could not create MediaElementSource", e);
      }

      const combinedStream = new MediaStream([
        ...stream.getVideoTracks(),
        ...dest.stream.getAudioTracks()
      ]);

      const mimeType = MediaRecorder.isTypeSupported("video/mp4") ? "video/mp4" : "video/webm";
      const recorder = new MediaRecorder(combinedStream, { mimeType, videoBitsPerSecond: 5000000 });
      const chunks: BlobPart[] = [];

      recorder.ondataavailable = (e) => { if (e.data.size > 0) chunks.push(e.data); };
      recorder.onstop = () => {
        const blob = new Blob(chunks, { type: mimeType });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `${result.fileName || 'dubbed_video'}.mp4`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        setIsRendering(false);
        setIsPlaying(false);
        if (videoRef.current) {
            videoRef.current.playbackRate = 1;
            videoRef.current.volume = 1; 
        }
      };

      recorder.start();

      const playbackRate = getSyncFactor();
      videoRef.current.playbackRate = playbackRate;
      videoRef.current.currentTime = 0;
      videoRef.current.volume = bgVolume; 

      await videoRef.current.play();
      ttsSource.start(0);
      ttsSourceRef.current = ttsSource; 

      ttsSource.onended = () => {
        recorder.stop();
        videoRef.current?.pause();
      };

    } catch (e) {
      console.error("Recording failed", e);
      setIsRendering(false);
      alert("Yuklashda xatolik yuz berdi. Iltimos, qayta urinib ko'ring.");
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">

        {/* Left: Video */}
        <div className="bg-gray-800 rounded-xl p-4 shadow-lg border border-gray-700">
          <h3 className="text-lg font-semibold mb-3 text-blue-300">
            Natija {isRendering && <span className="ml-2 text-xs text-red-400 animate-pulse">● Yozilmoqda...</span>}
          </h3>
          <div className="relative aspect-[9/16] bg-black rounded-lg overflow-hidden mx-auto max-h-[500px]">
            <video 
              ref={videoRef}
              src={videoUrl}
              className="w-full h-full object-contain"
              playsInline
              controls={false}
            />
          </div>

          <div className="flex gap-4 mt-4">
            {/* Volume Control */}
