              controls={false}
            />
            {/* Sync Status Overlay */}
            <div className="absolute top-2 left-2 right-2 bg-black/60 backdrop-blur-sm rounded px-3 py-2 text-xs text-white border border-white/10">
              <div className="flex justify-between mb-1 opacity-80">
                <span>Original Video: {formatTime(syncStats.videoDur)}</span>
                <span>Yangi Audio: {formatTime(syncStats.audioDur)}</span>
              </div>
              <div className={`font-bold border-t border-white/10 pt-1 ${syncStats.rate < 0.95 ? 'text-yellow-400' : (syncStats.rate > 1.05 ? 'text-blue-400' : 'text-green-400')}`}>
                 {syncStats.rate < 0.98 
                    ? `⚠️ Video ${Math.round((1 - syncStats.rate) * 100)}% ga sekinlashtirildi (Audio uzunroq)`
                    : syncStats.rate > 1.02 
                      ? `⚡ Video ${Math.round((syncStats.rate - 1) * 100)}% ga tezlashtirildi`
                      : `✅ Video va Audio mos`}
              </div>
            </div>
          </div>

          <div className="flex gap-4 mt-4">
            {/* Volume Control */}
            <div className="flex-1 bg-gray-900/50 p-3 rounded-lg border border-gray-600">
              <div className="flex justify-between text-xs text-gray-400 mb-1">
