import { GoogleGenAI, Modality } from "@google/genai";
import { fileToGenerativePart, decodeAudioData } from "../utils/audioUtils";

const apiKey = process.env.API_KEY || '';

// 1. Analyze Video: English Audio -> Uzbek Text & Topic & Voice Tone
export const analyzeAndTranslateVideo = async (videoFile: File, duration: number): Promise<{ translatedText: string; originalTranscription: string; topicSlug: string; recommendedVoice: string }> => {
  if (!apiKey) throw new Error("API Key topilmadi. Iltimos, API kaliti sozlanganligini tekshiring.");

  const ai = new GoogleGenAI({ apiKey });

  const videoPart = await fileToGenerativePart(videoFile);

  // We calculate approx word count needed. 
  // Average speaking rate is ~2-2.5 words per second for clear TTS.
  const targetWordCount = Math.max(5, Math.ceil(duration * 2.2)); 

  const prompt = `
    You are a professional Content Localizer and Dubbing Director for the Uzbek market.
    Your goal is NOT just to translate, but to fully convey the MEANING, CONTEXT, and EMOTION of the video.

    METADATA:
    - Video Duration: ${Math.ceil(duration)} seconds.
    - Target Word Count: Approximately ${targetWordCount} words (Adjust to match the video's pacing).

    TASKS:
    1. **ANALYZE DEEPLY (Visuals + Audio):** 
       - Listen to the speech AND look at the video frames. 
       - Understand what is actually happening, not just what is being said.

    2. **CREATIVE ADAPTATION (CRITICAL):** 
       - **Do NOT translate word-for-word.** Literal translation is forbidden if it sounds dry.
       - **Convey the Full Meaning:** If the speaker uses a short English phrase but the visual context implies a larger concept, EXPLAIN IT in Uzbek. 
       - **Localization:** Use natural, modern Uzbek (Instagram/TikTok style). Use metaphors or idioms that Uzbeks understand if they fit the context.
       - **Visual Narration:** If the speaker says "Look at this" but doesn't describe it, you MUST describe what "this" is in the Uzbek dub (e.g., instead of "Bunga qarang", say "Mana bu ajoyib manzaraga qarang").
       - **Objective:** The Uzbek listener should understand the video BETTER than someone just listening to the English audio.

    3. **TIMING & PACING:** 
       - The Uzbek text length MUST match the video flow.
       - If the video is fast-paced, keep it punchy.
       - If the video is slow and atmospheric, use richer, descriptive words to fill the silence naturally.

    4. **VOICE MATCHING:** Listen to the original speaker's gender and tone.
       - If FEMALE: Select 'Kore' (Natural/Clear) or 'Zephyr' (Soft/Calm).
       - If MALE: Select 'Puck' (Natural/Mid), 'Charon' (Deep/Calm), or 'Fenrir' (Deep/Intense/Narrator).

    5. **TOPIC:** Create a file-safe slug (e.g. 'tuxum_haqida').

    Output JSON format:
    {
      "english_transcription": "Transcription of the original audio...",
      "uzbek_translation": "The adapted, rich, and context-aware Uzbek narration...",
      "topic_slug": "short_topic_name",
      "recommended_voice": "VoiceName"
    }
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: {
      parts: [
        videoPart,
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from Gemini.");

  try {
    const json = JSON.parse(text);
    return {
      translatedText: json.uzbek_translation,
      originalTranscription: json.english_transcription,
      topicSlug: json.topic_slug || 'video_dublyaj',
      recommendedVoice: json.recommended_voice || 'Fenrir' // Default to Fenrir if failed
    };
  } catch (e) {
    console.error("Failed to parse JSON", e);
    return { 
      translatedText: text, 
      originalTranscription: "Not available",
      topicSlug: 'video_dublyaj',
      recommendedVoice: 'Fenrir'
    };
  }
};

// 2. Generate Audio: Uzbek Text -> Audio Buffer (Now accepts voiceName)
export const generateUzbekSpeech = async (text: string, audioContext: AudioContext, voiceName: string = 'Fenrir'): Promise<AudioBuffer> => {
  if (!apiKey) throw new Error("API Key topilmadi. Iltimos, API kaliti sozlanganligini tekshiring.");

  const ai = new GoogleGenAI({ apiKey });

  console.log(`Generating speech with voice: ${voiceName}`);

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: text }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error("No audio data returned from Gemini.");
  }

  return await decodeAudioData(base64Audio, audioContext, 24000, 1);
};

import React, { ChangeEvent, useState } from 'react';

interface VideoUploaderProps {
  onFileSelect: (file: File) => void;
  disabled: boolean;
}

const VideoUploader: React.FC<VideoUploaderProps> = ({ onFileSelect, disabled }) => {
  const [activeTab, setActiveTab] = useState<'file' | 'url'>('file');
  const [url, setUrl] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Reduced limit to 10MB to ensure stability with Gemini API (browser fetch limits)
  const MAX_SIZE_BYTES = 10 * 1024 * 1024; // 10MB

  const handleFileChange = (e: ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const file = e.target.files[0];

      if (file.size > MAX_SIZE_BYTES) {
        alert("Fayl hajmi juda katta! Barqaror ishlash uchun 10MB gacha bo'lgan videolarni yuklang.");
        e.target.value = ''; // Reset input
        return;
      }

      onFileSelect(file);
    }
  };

  const handleUrlSubmit = async () => {
    if (!url.trim()) return;

    // Pre-check for known CORS-blocking domains to avoid "Failed to fetch" errors
    const lowerUrl = url.toLowerCase();
    if (lowerUrl.includes('instagram.com') || lowerUrl.includes('youtube.com') || lowerUrl.includes('youtu.be') || lowerUrl.includes('tiktok.com')) {
       setError("Instagram, YouTube va TikTok havolalari xavfsizlik (CORS) sababli to'g'ridan-to'g'ri ishlamaydi. Iltimos, videoni yuklab olib, 'Fayl Yuklash' orqali kiriting.");
       return;
    }

    setIsLoading(true);
    setError(null);

    try {
      // Attempt to fetch
      const response = await fetch(url);

      if (!response.ok) {
        throw new Error(`Linkdan yuklab bo'lmadi. Status: ${response.status}`);
      }

      const blob = await response.blob();

      if (blob.size > MAX_SIZE_BYTES) {
        throw new Error("Video hajmi 10MB dan katta. Iltimos, kichikroq video (hikoya/reels) yuklang.");
      }

      const contentType = response.headers.get("content-type");

      if (contentType && !contentType.startsWith('video/')) {
         throw new Error("Kiritilgan havola video fayl emas.");
      }

      // Generate a generic filename or extract from URL
      const fileName = "downloaded_video.mp4";
      const file = new File([blob], fileName, { type: contentType || 'video/mp4' });

      onFileSelect(file);
    } catch (err: any) {
      console.error(err);
      let msg = "Ushbu havoladan to'g'ridan-to'g'ri yuklab bo'lmadi.";

      if (err.message.includes('Failed to fetch')) {
        msg = "Havola ochilmadi (CORS cheklovi). Sayt ruxsat bermadi. Iltimos, videoni qurilmangizga saqlab, fayl sifatida yuklang.";
      } else if (err.message.includes('10MB')) {
        msg = err.message;
      }

      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full max-w-xl mx-auto mb-8">
      {/* Tabs */}
      <div className="flex mb-4 bg-gray-800 rounded-lg p-1 border border-gray-700">
        <button
          onClick={() => { setActiveTab('file'); setError(null); }}
          disabled={disabled}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all duration-200 ${
            activeTab === 'file' 
              ? 'bg-gray-700 text-white shadow-sm' 
              : 'text-gray-400 hover:text-gray-200'
          }`}
        >
          Fayl Yuklash
        </button>
        <button
          onClick={() => { setActiveTab('url'); setError(null); }}
          disabled={disabled}
          className={`flex-1 py-2 text-sm font-medium rounded-md transition-all duration-200 ${
            activeTab === 'url' 
              ? 'bg-gray-700 text-white shadow-sm' 
              : 'text-gray-400 hover:text-gray-200'
          }`}
        >
          Link orqali
        </button>
      </div>

      {/* Tab Content: File Upload */}
      {activeTab === 'file' && (
        <label 
          htmlFor="video-upload" 
          className={`
            flex flex-col items-center justify-center w-full h-64 border-2 border-dashed rounded-lg cursor-pointer 
            transition-colors duration-300
            ${disabled 
              ? 'border-gray-600 bg-gray-800 opacity-50 cursor-not-allowed' 
              : 'border-blue-500 bg-gray-800 hover:bg-gray-750 hover:border-blue-400'}
          `}
        >
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <svg className="w-12 h-12 mb-4 text-blue-400" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 16">
              <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 13h3a3 3 0 0 0 0-6h-.025A5.56 5.56 0 0 0 16 6.5 5.5 5.5 0 0 0 5.207 5.021C5.137 5.017 5.071 5 5 5a4 4 0 0 0 0 8h2.167M10 15V6m0 0L8 8m2-2 2 2"/>
            </svg>
            <p className="mb-2 text-sm text-gray-300"><span className="font-semibold">Video yuklash uchun bosing</span></p>
            <p className="text-xs text-gray-400">MP4, MOV (max 10MB)</p>
          </div>
          <input 
            id="video-upload" 
            type="file" 
            accept="video/*" 
            className="hidden" 
            onChange={handleFileChange}
            disabled={disabled}
          />
        </label>
      )}

      {/* Tab Content: URL Upload */}
      {activeTab === 'url' && (
        <div className="bg-gray-800 border border-gray-700 rounded-lg p-6 flex flex-col justify-center">
          <div className="w-full">
            <label htmlFor="url-input" className="block text-sm font-medium text-gray-300 mb-2">
              Video Linki (MP4)
            </label>
            <div className="flex gap-2">
              <input
                id="url-input"
                type="url"
                placeholder="https://example.com/video.mp4"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                disabled={disabled || isLoading}
                className="flex-1 bg-gray-900 border border-gray-600 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5 placeholder-gray-500"
              />
              <button
                onClick={handleUrlSubmit}
                disabled={disabled || isLoading || !url}
                className={`
                  text-white bg-blue-600 hover:bg-blue-700 focus:ring-4 focus:ring-blue-800 font-medium rounded-lg text-sm px-5 py-2.5 text-center
                  disabled:opacity-50 disabled:cursor-not-allowed transition-colors flex items-center
                `}
              >
                {isLoading ? (
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                ) : (
                  'Yuklash'
                )}
              </button>
            </div>

            {error && (
              <div className="mt-4 p-3 text-sm text-red-200 bg-red-900/30 border border-red-800/50 rounded-lg">
                <span className="font-bold">Xatolik:</span> {error}
              </div>
            )}

            <div className="mt-6 p-4 bg-gray-700/30 rounded-lg border border-gray-600/50">
               <h4 className="text-sm font-semibold text-blue-300 mb-2 flex items-center gap-2">
                 <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                 Instagram yoki YouTube?
               </h4>
               <p className="text-xs text-gray-400 mb-2 leading-relaxed">
                 Afsuski, Instagram va YouTube xavfsizlik (CORS) tufayli havolani to'g'ridan-to'g'ri qabul qilmaydi.
               </p>
               <div className="text-xs text-gray-300">
                 <span className="block mb-1">Tavsiya etilgan usul:</span>
                 <ol className="list-decimal list-inside space-y-1 pl-1">
                   <li>Videoni <a href="https://snapinsta.app/" target="_blank" rel="noopener noreferrer" className="text-blue-400 hover:text-blue-300 underline">SnapInsta</a> kabi saytlardan yuklab oling.</li>
                   <li>"Fayl Yuklash" bo'limi orqali yuklang.</li>
                 </ol>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

